            "minItems": 1,
            "uniqueItems": true,
            "items": {"type": "string", "minLength": 1}
          },
          "citations": {
            "type": "array",
            "minItems": 1,
            "items": {
              "type": "object",
              "required": ["doc_id", "clause_no"],
              "properties": {
